func (q *Queries) EnabledFeeds(ctx context.Context) ([]Feed, error) {
	rows, err := q.db.Query(ctx, enabledFeeds)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []Feed{}
	for rows.Next() {
		var i Feed
		if err := rows.Scan(
			&i.ID,
			&i.Url,
			&i.Name,
			&i.Schedule,
			&i.Topics,
			&i.Enabled,
			&i.Etag,
			&i.LastModified,
			&i.LastFetchedAt,
			&i.ConsecutiveFailures,
			&i.LastError,
			&i.DisabledReason,
			&i.FilterConfig,
			&i.CreatedAt,
			&i.UpdatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

